export class NumReel {
 // PORT_NOTE[D2TS:visibility-block]:
 // reason: D visibility block syntax is unsupported in TS.
 // original: private:
  static readonly VEL_MIN: number = 5;
  static rand: Rand;
  deg: number;
  _targetDeg: number;
  ofs: number;
  velRatio: number;

  // PORT_NOTE[D2TS:invariant]: removed D invariant block

  static {
    rand = new Rand();
  }

  public static setRandSeed(seed: number): void {
    NumReel.rand.setSeed(seed);
  }

  public constructor() {
    this.init();
  }

  private init(): void {
    this.deg = this._targetDeg = 0;
    this.ofs = 0;
    this.velRatio = 1;
  }

  public clear(): void {
    this.init();
  }

  public move(): void {
    let vd: number = this._targetDeg - this.deg;
    vd *= 0.05 * this.velRatio;
    if (vd < NumReel.VEL_MIN * this.velRatio)
      vd = NumReel.VEL_MIN * this.velRatio;
    this.deg += vd;
    if (this.deg > this._targetDeg)
      this.deg = this._targetDeg;
  }

  public draw(x: number, y: number, s: number): void {
    let n: number = /* D_CAST(int) */ ((this.deg * 10 / 360 + 0.99) + 1) % 10;
    let d: number = this.deg % 360;
    let od: number = d - n * 360 / 10;
    od -= 15;
    Math.normalizeDeg360(od);
    od *= 1.5;
    for (let i = 0; i < 3; i++) {
      glPushMatrix();
      if (this.ofs > 0.005)
        glTranslatef(x + NumReel.rand.nextSignedFloat(1) * this.ofs, y + NumReel.rand.nextSignedFloat(1) * this.ofs, 0);
      else
        glTranslatef(x, y, 0);
      glRotatef(od, 1, 0, 0);
      glTranslatef(0, 0, s * 2.4);
      glScalef(s, -s, s);
      let a: number = 1 - fabs((od + 15) / (360 / 10 * 1.5)) / 2;
      if (a < 0)
        a = 0;
      Screen.setColor(a, a, a);
      Letter.drawLetter(n, 2);
      Screen.setColor(a / 2, a / 2, a / 2);
      Letter.drawLetter(n, 3);
      glPopMatrix();
      n--;
      if (n < 0)
        n = 9;
      od += 360 / 10 * 1.5;
      Math.normalizeDeg360(od);
    }
    this.ofs *= 0.95;
  }

  public targetDeg(td: number): void {
    if ((td - this._targetDeg) > 1)
      this.ofs += 0.1;
    return this._targetDeg = td;
  }

  public accelerate(): void {
    this.velRatio = 4;
  }
}

